// // This module implements a gated D flip-flop with synchronous reset functionality. It captures the inverted value of the input D on the falling edge of the clock (CLK) and sets the output nQ to HIGH when the active high reset signal (RESET) is asserted.
module top_module(input D, CLK, nSET, output reg nQ);parameter [0:0] INIT = 1'bx; 
  initial nQ = INIT; 
  always @(posedge CLK, negedge nSET) begin 
  if (!nSET) 
  nQ <= 1'b0; 
  else 
  nQ <= ~D; 
  end 
 endmodule
